  ('judicial-0b5ab5d8-moex-00007', 'judicial-0b5ab5d8', 'judicial-0b5ab5d8-moex-114-916530c6', 'sub-judicial-0b5ab5d8-02', NULL, 'essay', '約十餘名幫派分子聚集於一間座落於市區交通樞紐道路旁的夜店門口，
在甲命令下叫囂、占據車道，以及阻擋出入口，致使該夜店與周邊商家
的顧客驚恐走避。見到警方到場後，甲反而透過網路直播號召更多人前
來圍堵警車與推倒交通錐。警員A在維持交通秩序時，遭幫派分子乙揮
拳擊中臉部，導致其鼻樑流血，其他幫派分子鼓譟說：「打得好！就該這
樣！」面對被群眾阻塞的車道，急著送哮喘孩童B就醫的丙，以及急著
趕時間出國搭機的丁、戊三人共同決意開車衝入人群，強行開闢一條通
路。未料，丙車被攔下，丙、丁、戊因執意通行，隨即與甲、乙等幫派
分子爆發激烈肢體衝突，混亂中被捲入群毆的路人 C，於參與群毆時受
到驚嚇，導致心臟病發死亡。試分析甲、乙、丙、丁、戊前述行為可能
涉及的刑事責任。（25分）', '[]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:03+00:00", "source_pdf_sha1": "b1018aad378e", "answer_pdf_sha1": null, "source_family": "moex-gov-tw", "moex": {"exam_code": "114120", "c": "108", "s": "0503", "q": "1"}, "raw_section_label": "甲、申論題部分", "subject": "刑法", "year": "114", "exam_name": "114年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、未具擬任職務任用資格取得法官遴選資格考試", "original_question_number": "四", "answer_corrected": false, "flags": [], "civil_slug": "judicial", "civil_category": "檢察事務官-偵查實務組"}'::jsonb, NULL),
