  ('judicial-0b5ab5d8-moex-00015', 'judicial-0b5ab5d8', 'judicial-0b5ab5d8-moex-114-2c6191fe', 'sub-judicial-0b5ab5d8-05', NULL, 'essay', '甲先後於民國（下同）93 年間、94 年間、95 年間以無息無擔保方式貸
與其長子乙新臺幣（下同）250萬元（以下稱 A債權）、150萬元（以下
稱 B債權）、200萬元（以下稱 C債權），並約定上述各債務均自貸與日
起經一年後為清償期。上述各債務之清償期先後屆至後，乙均未按期清
償，經甲再三催促，乙於98 年間先償還予甲 150萬元，其後即未再為清
償。甲於103年間死亡，其長女丙依甲之遺囑繼承 A、B、C債權後，數
次催促乙清償上述積欠餘款未果，乃於 111 年間起訴請求乙返還上述合
計 450萬元之全部借款。乙於訴訟過程中主張丙所請求款項均已罹於時
效，是否有理？（25分）', '[]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:03+00:00", "source_pdf_sha1": "13371f7c21b8", "answer_pdf_sha1": null, "source_family": "moex-gov-tw", "moex": {"exam_code": "114120", "c": "108", "s": "0403", "q": "1"}, "raw_section_label": "甲、申論題部分", "subject": "民法總則與債權、物權編", "year": "114", "exam_name": "114年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、未具擬任職務任用資格取得法官遴選資格考試", "original_question_number": "一", "answer_corrected": false, "flags": [], "civil_slug": "judicial", "civil_category": "檢察事務官-偵查實務組"}'::jsonb, NULL)
